private static char[] test(char[] cs) {
  int j = 0;
  for(int i = 0; i < cs.length; i ++) {
    if(cs[i] == 'a') continue;
    if(cs[i] == 'b') {
      int b = 0, c = 0;
      while(cs[i] == 'b' || cs[i] == 'c'){
        if (cs[i] == 'b') b ++;
        else c ++;
        i ++;
      }
      int t = Math.abs(b-c);
      char cr = b > c ? 'b' : 'c';
      while(t-- > 0) cs[j++] = cr;
    } else {
      cs[j ++] = cs[i];
    }
  }
  while(j < cs.length) {
    cs[j ++] = '0';
  }
  return cs;
}
